parameters.jsCode:
// Grab all items from Hybrid Search
const items = $input.all();

// Extract content from each document into a flat array
const documents = items.map(item => item.json.content);

// Pull the original query from the workflow input
const query = $('When Executed by Another Workflow').first().json.query;

// Return a single item — one batched call to Cohere
return [
  {
    json: {
      query,
      documents,
    },
  },
];

// Cohere results — already sorted by relevance_score descending
const cohereResults = $input.first().json.results;

// Original full documents from Hybrid Search (before we extracted content)
const hybridItems = $('Hybrid Search').all();

// Map each Cohere index back to the original document, inject relevance_score
const reranked = cohereResults.map(result => ({
  json: {
    ...hybridItems[result.index].json,
    relevance_score: result.relevance_score,
  },
}));

return reranked;

